#!/bin/bash
# =============================================================================
# Prepare and optionally submit GfKb revision jobs from the final repo.
#
# P0: Qwen3-0.6B decile/discrete/RoPE fused vs unfused
# P1: Llama 10-epoch sweep uses the generated 02/04/06 jobfiles in this folder.
# =============================================================================

set -euo pipefail

MODE="${1:---prepare-only}"
CPU_PARTITION="tier3q"
GPU_PARTITION="sxmq"
# cri22cn501 currently has active/orphan processes on GPUs 0-3. For revision
# GPU jobs, reserve the full SXM node and pin work to GPUs 4-7 in the runner.
SXMQ_SAFE_GRES="gpu:8"
SXMQ_SAFE_ARRAY_LIMIT="${SXMQ_SAFE_ARRAY_LIMIT:-10}"
SXMQ_REQUEUE_SIGNAL="${SXMQ_REQUEUE_SIGNAL:-B:USR1@900}"
SXMQ_TIME_LIMIT="${SXMQ_TIME_LIMIT:-10-00:00:00}"
SXMQ_QOS="${SXMQ_QOS:-normal}"
WANDB_PROJECT="input-rep-benchmark-revision-gfkb"
REV_TOKENIZED_DIR="artifacts/runs/tokenized/mimiciv-3.1_meds_70-10-20"
ABS_REV_TOKENIZED_DIR="/gpfs/data/bbj-lab/users/daniel/input-representation-benchmark/${REV_TOKENIZED_DIR}"
ABS_IRB_HOME="/gpfs/data/bbj-lab/users/daniel/input-representation-benchmark"
ABS_FMS_EHRS_HOME="/gpfs/data/bbj-lab/users/daniel/fms-ehrs"

find_repo_root() {
  local d="$1"
  while [[ "$d" != "/" ]]; do
    if [[ -f "$d/pipeline/run_experiments.py" && -d "$d/slurm" ]]; then
      echo "$d"
      return 0
    fi
    d="$(dirname "$d")"
  done
  return 1
}

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
IRB_HOME="$(find_repo_root "${SCRIPT_DIR}")"
cd "${IRB_HOME}"

REV_DIR="${IRB_HOME}/slurm/generated/revision_gfkb"
mkdir -p "${REV_DIR}" "${IRB_HOME}/slurm/output"

cat > "${REV_DIR}/01_stage1_qwen3.jobfile" <<'EOF'
# revision Stage 1 Qwen3 fused-vs-unfused
# Generated by slurm/17_prepare_submit_revision_gfkb.sh

IRB_MODEL_NAME=Qwen/Qwen3-0.6B IRB_MODEL_VERSION_PREFIX=qwen3_0p6b_exp2 IRB_USE_MODEL_CONFIG_OVERRIDES=false IRB_WANDB_PROJECT=input-rep-benchmark-revision-gfkb IRB_REQUIRE_WANDB=true WANDB_MODE=online IRB_RESUME_FROM_CHECKPOINT=auto IRB_STAGE1_SAVE_STRATEGY=steps IRB_STAGE1_SAVE_STEPS=2000 IRB_STAGE1_SAVE_TOTAL_LIMIT=3 IRB_STAGE1_EVAL_STRATEGY=epoch IRB_LOAD_BEST_MODEL_AT_END=false IRB_TOKENIZED_DATASET_DIR=artifacts/runs/tokenized/mimiciv-3.1_meds_70-10-20 IRB_EXP23_STAGE1_EPOCHS=1 IRB_RUN_JID=s42-ep1-gpu4-r3 bash slurm/07_exp2_stage1_train_representation.sh --config_id meds_deciles_none_fusedFalse_discrete_time_rope --data_version deciles_none_unfused_time_rope --representation discrete --temporal time_rope --num_bins 10 --seed 42
IRB_MODEL_NAME=Qwen/Qwen3-0.6B IRB_MODEL_VERSION_PREFIX=qwen3_0p6b_exp2 IRB_USE_MODEL_CONFIG_OVERRIDES=false IRB_WANDB_PROJECT=input-rep-benchmark-revision-gfkb IRB_REQUIRE_WANDB=true WANDB_MODE=online IRB_RESUME_FROM_CHECKPOINT=auto IRB_STAGE1_SAVE_STRATEGY=steps IRB_STAGE1_SAVE_STEPS=2000 IRB_STAGE1_SAVE_TOTAL_LIMIT=3 IRB_STAGE1_EVAL_STRATEGY=epoch IRB_LOAD_BEST_MODEL_AT_END=false IRB_TOKENIZED_DATASET_DIR=artifacts/runs/tokenized/mimiciv-3.1_meds_70-10-20 IRB_EXP23_STAGE1_EPOCHS=1 IRB_RUN_JID=s42-ep1-gpu4-r3 bash slurm/07_exp2_stage1_train_representation.sh --config_id meds_deciles_none_fusedTrue_discrete_time_rope --data_version deciles_none_fused_time_rope --representation discrete --temporal time_rope --num_bins 10 --seed 42
EOF

awk 'NF && $1 !~ /^#/ {print; exit}' "${REV_DIR}/01_stage1_qwen3.jobfile" > "${REV_DIR}/01a_stage1_qwen3_unfused.jobfile"
sed -i '1i# Generated by slurm/17_prepare_submit_revision_gfkb.sh' "${REV_DIR}/01a_stage1_qwen3_unfused.jobfile"
sed -i '1i# revision Stage 1 Qwen3 unfused' "${REV_DIR}/01a_stage1_qwen3_unfused.jobfile"
awk 'NF && $1 !~ /^#/ {n+=1; if (n==2) print}' "${REV_DIR}/01_stage1_qwen3.jobfile" > "${REV_DIR}/01b_stage1_qwen3_fused.jobfile"
sed -i '1i# Generated by slurm/17_prepare_submit_revision_gfkb.sh' "${REV_DIR}/01b_stage1_qwen3_fused.jobfile"
