echo "[prepare] wrote Qwen revision jobfiles under ${REV_DIR}"

STATE_FILE="${REV_DIR}/submit_state.env"

if [[ "${MODE}" == "--prepare-only" ]]; then
  exit 0
fi

usage() {
  echo "Usage: bash slurm/17_prepare_submit_revision_gfkb.sh [MODE] [OPTIONS]" >&2
  echo "  --prepare-only              Regenerate jobfiles only (default)" >&2
  echo "  --submit-qwen               Submit Qwen Stage 1-3 + stats chain (P0)" >&2
  echo "  --submit-qwen-scaled        Submit Qwen depth8/depth16 chain first" >&2
  echo "  --submit-llama              Submit Llama 10-epoch chain after Qwen completes (P1)" >&2
  echo "      --after-job JOBID       Upstream Qwen job to wait on (optional if in state file)" >&2
  echo "  --submit-llama-now          Submit Llama 10-epoch chain immediately on sxmq (no upstream wait)" >&2
  echo "  --submit-llama-after-scaled Submit Llama chain after Qwen scaled stats" >&2
  echo "  --submit-full               Submit original Qwen chain, then Llama chain" >&2
  echo "  --submit-revision-full      Submit Qwen scaled chain, then Llama chain" >&2
  exit 2
}

count_cmds() {
  awk 'NF && $1 !~ /^#/{n+=1} END{print n+0}' "$1"
}

dep_afterok() {
  local dep=""
  local jid
  for jid in "$@"; do
    if [[ -n "${dep}" ]]; then
      dep="${dep},afterok:${jid}"
    else
      dep="afterok:${jid}"
    fi
  done
  echo "${dep}"
}

submit_array() {
  local partition="$1"
  local dependency="$2"
  local runner="$3"
  local jobfile="$4"
  local n
  n="$(count_cmds "${jobfile}")"
  if [[ "${n}" -le 0 ]]; then
    echo "ERROR: no commands in ${jobfile}" >&2
    exit 1
  fi
  if [[ -n "${dependency}" ]]; then
    sbatch --parsable --partition="${partition}" --dependency="${dependency}" --array="0-$((n - 1))" "${runner}" "${jobfile}"
  else
    sbatch --parsable --partition="${partition}" --array="0-$((n - 1))" "${runner}" "${jobfile}"
  fi
}

submit_array_sxmq_safe() {
  local dependency="$1"
  local runner="$2"
  local jobfile="$3"
  local n
  n="$(count_cmds "${jobfile}")"
  if [[ "${n}" -le 0 ]]; then
    echo "ERROR: no commands in ${jobfile}" >&2
    exit 1
  fi
  local array_spec="0-$((n - 1))%${SXMQ_SAFE_ARRAY_LIMIT}"
  if [[ -n "${dependency}" ]]; then
    sbatch --parsable --partition="${GPU_PARTITION}" --qos="${SXMQ_QOS}" --gres="${SXMQ_SAFE_GRES}" --time="${SXMQ_TIME_LIMIT}" --dependency="${dependency}" --array="${array_spec}" "${runner}" "${jobfile}"
  else
    sbatch --parsable --partition="${GPU_PARTITION}" --qos="${SXMQ_QOS}" --gres="${SXMQ_SAFE_GRES}" --time="${SXMQ_TIME_LIMIT}" --array="${array_spec}" "${runner}" "${jobfile}"
  fi
}

submit_array_sxmq_requeue_safe() {
  local dependency="$1"
  local runner="$2"
  local jobfile="$3"
  local n
  n="$(count_cmds "${jobfile}")"
  if [[ "${n}" -le 0 ]]; then
    echo "ERROR: no commands in ${jobfile}" >&2
    exit 1
  fi
  local array_spec="0-$((n - 1))%${SXMQ_SAFE_ARRAY_LIMIT}"
  if [[ -n "${dependency}" ]]; then
    sbatch --parsable --partition="${GPU_PARTITION}" --qos="${SXMQ_QOS}" --gres="${SXMQ_SAFE_GRES}" --time="${SXMQ_TIME_LIMIT}" --requeue --signal="${SXMQ_REQUEUE_SIGNAL}" --dependency="${dependency}" --array="${array_spec}" "${runner}" "${jobfile}"
  else
    sbatch --parsable --partition="${GPU_PARTITION}" --qos="${SXMQ_QOS}" --gres="${SXMQ_SAFE_GRES}" --time="${SXMQ_TIME_LIMIT}" --requeue --signal="${SXMQ_REQUEUE_SIGNAL}" --array="${array_spec}" "${runner}" "${jobfile}"
  fi
}

submit_single() {
  local partition="$1"
  local dependency="$2"
  local runner="$3"
  local jobfile="$4"
  if [[ "$(count_cmds "${jobfile}")" -ne 1 ]]; then
    echo "ERROR: expected exactly one command in ${jobfile}" >&2
    exit 1
  fi
  if [[ -n "${dependency}" ]]; then
    sbatch --parsable --partition="${partition}" --dependency="${dependency}" --array=0 "${runner}" "${jobfile}"
  else
    sbatch --parsable --partition="${partition}" --array=0 "${runner}" "${jobfile}"
  fi
}

write_submit_state() {
  local saved_llama_train="${JID_LLAMA_TRAIN:-}"
  local saved_llama_extract="${JID_LLAMA_EXTRACT:-}"
  local saved_llama_lr="${JID_LLAMA_LR:-}"
  local saved_llama_stats="${JID_LLAMA_STATS:-}"
  local existing_qwen_unfused="" existing_qwen_fused="" existing_qwen_extract=""
  local existing_qwen_lr="" existing_qwen_stats="" existing_qwen_combine=""
  local existing_qwen_scaled_train="" existing_qwen_scaled_extract=""
  local existing_qwen_scaled_lr="" existing_qwen_scaled_stats=""
  if [[ -f "${STATE_FILE}" ]]; then
    # shellcheck disable=SC1090
    source "${STATE_FILE}"
    existing_qwen_unfused="${JID_QWEN_UNFUSED:-}"
    existing_qwen_fused="${JID_QWEN_FUSED:-}"
    existing_qwen_extract="${JID_QWEN_EXTRACT:-}"
    existing_qwen_lr="${JID_QWEN_LR:-}"
    existing_qwen_stats="${JID_QWEN_STATS:-}"
    existing_qwen_combine="${JID_QWEN_COMBINE:-}"
    existing_qwen_scaled_train="${JID_QWEN_SCALED_TRAIN:-}"
    existing_qwen_scaled_extract="${JID_QWEN_SCALED_EXTRACT:-}"
    existing_qwen_scaled_lr="${JID_QWEN_SCALED_LR:-}"
    existing_qwen_scaled_stats="${JID_QWEN_SCALED_STATS:-}"
  fi
  cat > "${STATE_FILE}" <<EOF
# Written by slurm/17_prepare_submit_revision_gfkb.sh on $(date -Iseconds)
JID_QWEN_UNFUSED=${JID_QWEN_UNFUSED:-${existing_qwen_unfused}}
JID_QWEN_FUSED=${JID_QWEN_FUSED:-${existing_qwen_fused}}
JID_QWEN_EXTRACT=${JID_QWEN_EXTRACT:-${existing_qwen_extract}}
JID_QWEN_LR=${JID_QWEN_LR:-${existing_qwen_lr}}
JID_QWEN_STATS=${JID_QWEN_STATS:-${existing_qwen_stats}}
JID_QWEN_COMBINE=${JID_QWEN_COMBINE:-${existing_qwen_combine}}
JID_QWEN_SCALED_TRAIN=${JID_QWEN_SCALED_TRAIN:-${existing_qwen_scaled_train}}
JID_QWEN_SCALED_EXTRACT=${JID_QWEN_SCALED_EXTRACT:-${existing_qwen_scaled_extract}}
JID_QWEN_SCALED_LR=${JID_QWEN_SCALED_LR:-${existing_qwen_scaled_lr}}
JID_QWEN_SCALED_STATS=${JID_QWEN_SCALED_STATS:-${existing_qwen_scaled_stats}}
JID_LLAMA_TRAIN=${saved_llama_train:-}
JID_LLAMA_EXTRACT=${saved_llama_extract:-}
JID_LLAMA_LR=${saved_llama_lr:-}
JID_LLAMA_STATS=${saved_llama_stats:-}
EOF
}

submit_qwen_chain() {
  echo "[submit] Qwen P0 chain (Stage 1 unfused+fused -> extract -> probes -> stats -> combine)..."
  JID_QWEN_UNFUSED="$(submit_array_sxmq_requeue_safe "" "slurm/05_run_stage1_gpu4_train.sh" "${REV_DIR}/01a_stage1_qwen3_unfused.jobfile")"
  JID_QWEN_FUSED="$(submit_array_sxmq_requeue_safe "" "slurm/05_run_stage1_gpu4_train.sh" "${REV_DIR}/01b_stage1_qwen3_fused.jobfile")"
  local dep_s1
  dep_s1="$(dep_afterok "${JID_QWEN_UNFUSED}_*" "${JID_QWEN_FUSED}_*")"
  JID_QWEN_EXTRACT="$(submit_array_sxmq_safe "${dep_s1}" "slurm/09_run_stage2_gpu2_extract.sh" "${REV_DIR}/03_stage2_qwen3_extract.jobfile")"
  JID_QWEN_LR="$(submit_array "${CPU_PARTITION}" "$(dep_afterok "${JID_QWEN_EXTRACT}_*")" "slurm/11_run_stage3_tier2q_lr.sh" "${REV_DIR}/05_stage3_qwen3_probes.jobfile")"
  JID_QWEN_STATS="$(submit_array "${CPU_PARTITION}" "$(dep_afterok "${JID_QWEN_LR}_*")" "slurm/15_run_stats_cpu_jobfile.sh" "${REV_DIR}/07a_stats_qwen3_families.jobfile")"
  JID_QWEN_COMBINE="$(sbatch --parsable --partition="${CPU_PARTITION}" --dependency="$(dep_afterok "${JID_QWEN_STATS}_*")" "slurm/15_run_stats_cpu_jobfile.sh" "${REV_DIR}/08_stats_combine.jobfile")"

  echo "[submit] qwen_unfused=${JID_QWEN_UNFUSED}"
  echo "[submit] qwen_fused=${JID_QWEN_FUSED}"
  echo "[submit] qwen_extract=${JID_QWEN_EXTRACT}"
  echo "[submit] qwen_lr=${JID_QWEN_LR}"
  echo "[submit] qwen_stats=${JID_QWEN_STATS}"
  echo "[submit] qwen_combine=${JID_QWEN_COMBINE}"
  write_submit_state
}

submit_qwen_scaled_chain() {
  echo "[submit] Qwen scaled chain (depth8/depth16 fused+unfused -> extract -> probes -> stats)..."
  JID_QWEN_SCALED_TRAIN="$(submit_array_sxmq_requeue_safe "" "slurm/05_run_stage1_gpu4_train.sh" "${REV_DIR}/09_stage1_qwen3_scaled.jobfile")"
  JID_QWEN_SCALED_EXTRACT="$(submit_array_sxmq_safe "$(dep_afterok "${JID_QWEN_SCALED_TRAIN}_*")" "slurm/09_run_stage2_gpu2_extract.sh" "${REV_DIR}/10_stage2_qwen3_scaled_extract.jobfile")"
  JID_QWEN_SCALED_LR="$(submit_array "${CPU_PARTITION}" "$(dep_afterok "${JID_QWEN_SCALED_EXTRACT}_*")" "slurm/11_run_stage3_tier2q_lr.sh" "${REV_DIR}/11_stage3_qwen3_scaled_probes.jobfile")"
  JID_QWEN_SCALED_STATS="$(submit_array "${CPU_PARTITION}" "$(dep_afterok "${JID_QWEN_SCALED_LR}_*")" "slurm/15_run_stats_cpu_jobfile.sh" "${REV_DIR}/12_stats_qwen3_scaled_families.jobfile")"

  echo "[submit] qwen_scaled_train=${JID_QWEN_SCALED_TRAIN}"
  echo "[submit] qwen_scaled_extract=${JID_QWEN_SCALED_EXTRACT}"
  echo "[submit] qwen_scaled_lr=${JID_QWEN_SCALED_LR}"
  echo "[submit] qwen_scaled_stats=${JID_QWEN_SCALED_STATS}"
  write_submit_state
}

submit_llama_chain() {
  local qwen_combine_jid="${1:-}"
  local dep_qwen=""
  if [[ -n "${qwen_combine_jid}" ]]; then
    echo "[submit] Llama P1 chain gated on afterok:${qwen_combine_jid}..."
    dep_qwen="$(dep_afterok "${qwen_combine_jid}")"
  else
    echo "[submit] Llama P1 chain on sxmq (no upstream dependency)..."
  fi
  JID_LLAMA_TRAIN="$(submit_array_sxmq_requeue_safe "${dep_qwen}" "slurm/05_run_stage1_gpu4_train.sh" "${REV_DIR}/02_stage1_llama10ep.jobfile")"
  JID_LLAMA_EXTRACT="$(submit_array_sxmq_safe "$(dep_afterok "${JID_LLAMA_TRAIN}_*")" "slurm/09_run_stage2_gpu2_extract.sh" "${REV_DIR}/04_stage2_llama10ep_extract.jobfile")"
  JID_LLAMA_LR="$(submit_array "${CPU_PARTITION}" "$(dep_afterok "${JID_LLAMA_EXTRACT}_*")" "slurm/11_run_stage3_tier2q_lr.sh" "${REV_DIR}/06_stage3_llama10ep_probes.jobfile")"
  JID_LLAMA_STATS="$(submit_array "${CPU_PARTITION}" "$(dep_afterok "${JID_LLAMA_LR}_*")" "slurm/15_run_stats_cpu_jobfile.sh" "${REV_DIR}/07b_stats_llama10ep_families.jobfile")"

  if [[ -n "${qwen_combine_jid}" ]]; then
    echo "[submit] llama_train=${JID_LLAMA_TRAIN} (depends on upstream=${qwen_combine_jid})"
  else
    echo "[submit] llama_train=${JID_LLAMA_TRAIN} (no upstream dependency)"
  fi
  echo "[submit] llama_extract=${JID_LLAMA_EXTRACT}"
  echo "[submit] llama_lr=${JID_LLAMA_LR}"
  echo "[submit] llama_stats=${JID_LLAMA_STATS}"
  write_submit_state
}

AFTER_JOB=""
if [[ "${MODE}" == "--submit-llama" || "${MODE}" == "--submit-llama-after-scaled" || "${MODE}" == "--submit-full" || "${MODE}" == "--submit-revision-full" ]]; then
  shift || true
  while [[ $# -gt 0 ]]; do
    case "$1" in
      --after-job)
        AFTER_JOB="$2"
        shift 2
        ;;
      *)
        usage
        ;;
    esac
  done
fi

case "${MODE}" in
  --submit-qwen)
    submit_qwen_chain
    ;;
  --submit-qwen-scaled)
    submit_qwen_scaled_chain
    ;;
  --submit-full)
    submit_qwen_chain
    submit_llama_chain "${JID_QWEN_COMBINE}"
    ;;
  --submit-revision-full)
    submit_qwen_scaled_chain
    submit_llama_chain "${JID_QWEN_SCALED_STATS}"
    ;;
  --submit-llama)
    if [[ -z "${AFTER_JOB}" && -f "${STATE_FILE}" ]]; then
      # shellcheck disable=SC1090
      source "${STATE_FILE}"
      AFTER_JOB="${JID_QWEN_COMBINE:-}"
    fi
    submit_llama_chain "${AFTER_JOB}"
    ;;
  --submit-llama-after-scaled)
    if [[ -z "${AFTER_JOB}" && -f "${STATE_FILE}" ]]; then
      # shellcheck disable=SC1090
      source "${STATE_FILE}"
      AFTER_JOB="${JID_QWEN_SCALED_STATS:-}"
    fi
    submit_llama_chain "${AFTER_JOB}"
    ;;
  --submit-llama-now)
    submit_llama_chain ""
    ;;
  *)
    usage
    ;;
esac
